tests:
def test_char_match():
    r = char('a')('apple')
    assert r.success and r.value == 'a' and r.remaining == 'pple'

def test_char_fail():
    r = char('a')('banana')
    assert r.success is False

def test_digit():
    r = digit()('7xyz')
    assert r.success and r.value == '7' and r.remaining == 'xyz'

def test_literal():
    r = literal('hello')('hello world')
    assert r.success and r.value == 'hello' and r.remaining == ' world'

def test_many_zero():
    r = digit().many()('abc')
    assert r.success and r.value == [] and r.remaining == 'abc'

def test_integer():
    assert integer()('42 rest').value == 42
    assert integer()('-17x').value == -17

def test_whitespace():
    r = whitespace()('   abc')
    assert r.success and r.remaining == 'abc'
